# my-support-agent/agent.py  (generated, then customized)
# The template provides the skeleton; the team fills in domain specifics.

import anthropic
from tools.retrieve import retrieve_chunks
from tools.synthesize import format_with_citations

SYSTEM_PROMPT = """
You are a support agent for Acme Corp. You answer questions about our
products using the retrieve_chunks tool to find relevant documentation.
Always cite the source document for every factual claim.
If you cannot find relevant information, say so — do not guess.
"""

# Tool definition — generated from template, names customized by team
TOOLS = [
    {
        "name": "retrieve_chunks",
        "description": "Retrieve relevant documentation chunks from the Acme knowledge base.",
        "input_schema": {
            "type": "object",
            "properties": {
                "query": {"type": "string", "description": "Search query"},
                "top_k": {"type": "integer", "default": 8}
            },
            "required": ["query"]
        }
    }
]

client = anthropic.Anthropic()

def run_support_agent(user_question: str) -> str:
    messages = [{"role": "user", "content": user_question}]

    while True:
        response = client.messages.create(
            model="claude-3-5-sonnet-20241022",
            max_tokens=2048,
            system=SYSTEM_PROMPT,
            tools=TOOLS,
            messages=messages,
        )

        if response.stop_reason == "end_turn":
            # Extract text content
            return next(
                block.text for block in response.content
                if hasattr(block, "text")
            )

        # Handle tool use
        messages.append({"role": "assistant", "content": response.content})
        tool_results = []
        for block in response.content:
            if block.type == "tool_use":
                chunks = retrieve_chunks(
                    query=block.input["query"],
                    top_k=block.input.get("top_k", 8)
                )
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": format_with_citations(chunks),
                })
        messages.append({"role": "user", "content": tool_results})
